TriggerOraclev10g.body:
DECLARE
    vta_pagos   pkgtkr_pagos_dao.t_tkr_pagos;
BEGIN
    IF :new.id IS NULL
    THEN
        :new.id := tkr_desembolsos_seq.NEXTVAL;
    END IF;

    :new.id_usuario_registra := f_usuario(NVL (v ('APP_USER'), USER));
    :new.fecha_registra := SYSTIMESTAMP AT TIME ZONE 'America/Bogota';
    IF :new.id_liquidacion is not null THEN
        pkgcn_liquidacion.p_pagos_x_profesional(:new.id_liquidacion, :new.id_usuario, vta_pagos);
        IF vta_pagos.count > 0 THEN
            FOR p IN vta_pagos.FIRST .. vta_pagos.LAST LOOP
                vta_pagos(p).id_estado_pago_profesional := 2;
                vta_pagos(p).id_desembolso := :new.id;
                pkgtkr_pagos_dao.p_actualizar(vta_pagos(p));
            END LOOP;
        END IF;
    END IF;
END;
